// Compress image before upload to prevent "Failed to fetch" from large files
// Compress image before upload to prevent "Failed to fetch" from large files
const compressImage = (file: File, maxWidth = 1024, quality = 0.6): Promise<File> => {
  return new Promise((resolve) => {
    // If not an image, return as-is
    if (!file.type.startsWith('image/')) {
      resolve(file);
      return;
    }

    // If it's already an image and relatively small (< 500KB), return as-is
    if (file.size < 500_000) {
      resolve(file);
      return;
    }

    const objectUrl = URL.createObjectURL(file);

    // Use createImageBitmap if available (more memory efficient for large S22 Ultra images)
    if ('createImageBitmap' in window) {
      createImageBitmap(file)
        .then((bitmap) => {
          const canvas = document.createElement('canvas');
          let { width, height } = bitmap;

          if (width > maxWidth) {
            height = (height * maxWidth) / width;
            width = maxWidth;
          }

          canvas.width = width;
          canvas.height = height;
          const ctx = canvas.getContext('2d');
          if (!ctx) {
            bitmap.close();
            resolve(file);
            return;
          }

          ctx.drawImage(bitmap, 0, 0, width, height);
          bitmap.close(); // Immediate cleanup

          canvas.toBlob((blob) => {
            if (blob) {
              const compressedFile = new File([blob], file.name.replace(/\.[^.]+$/, '.jpg'), {
                type: 'image/jpeg',
                lastModified: Date.now()
              });
              resolve(compressedFile);
            } else {
              resolve(file);
            }
            URL.revokeObjectURL(objectUrl);
          }, 'image/jpeg', quality);
        })
        .catch(() => {
          // Fallback to Image() if bitmap fails
          const img = new Image();
          img.onload = () => {
            const canvas = document.createElement('canvas');
            let w = img.width;
            let h = img.height;
            if (w > maxWidth) {
              h = (h * maxWidth) / w;
              w = maxWidth;
            }
            canvas.width = w;
            canvas.height = h;
            const ctx = canvas.getContext('2d');
            ctx?.drawImage(img, 0, 0, w, h);
            canvas.toBlob((blob) => {
              if (blob) resolve(new File([blob], file.name, { type: 'image/jpeg' }));
              else resolve(file);
              URL.revokeObjectURL(objectUrl);
              img.src = ""; // Clear memory safely
            }, 'image/jpeg', quality);
          };
          img.onerror = () => {
            URL.revokeObjectURL(objectUrl);
            resolve(file);
          };
          img.src = objectUrl;
        });
    } else {
      // Legacy fallback
      const img = new Image();
      img.onload = () => {
        URL.revokeObjectURL(objectUrl);
        const canvas = document.createElement('canvas');
        let { width, height } = img;
        if (width > maxWidth) {
          height = (height * maxWidth) / width;
          width = maxWidth;
        }
        canvas.width = width;
        canvas.height = height;
        const ctx = canvas.getContext('2d');
        if (ctx) ctx.drawImage(img, 0, 0, width, height);
        canvas.toBlob((blob) => {
          if (blob) resolve(new File([blob], file.name, { type: 'image/jpeg' }));
          else resolve(file);
          img.src = ""; // Clear memory safely
        }, 'image/jpeg', quality);
      };
      img.onerror = () => {
        URL.revokeObjectURL(objectUrl);
        resolve(file);
      };
      img.src = objectUrl;
    }
  });
};

